from pathlib import Path
path = Path('/home/ubuntu/crm-ai-relazionale-work/app/demo/page.tsx')
s = path.read_text()

s = s.replace("import { Bot, CheckSquare, ChevronRight, Database, Download, MessageSquareText, Pencil, Plus, Save, Search, Send, Trash2, TrendingUp, Upload, Users } from 'lucide-react'", "import { Bot, CheckSquare, ChevronRight, Database, Download, MessageSquareText, Pencil, Plus, Save, Search, Send, ShieldCheck, Trash2, TrendingUp, Upload, UserPlus, Users } from 'lucide-react'")

s = s.replace("type ConversationRecord = {\n  id: string\n  contactId: string\n  text: string\n  analysis: ConversationAnalysis\n  createdAt: string\n}\n\nconst STORAGE_KEY = 'relazione-crm-personale-v1'", "type ConversationRecord = {\n  id: string\n  contactId: string\n  text: string\n  analysis: ConversationAnalysis\n  createdAt: string\n}\n\ntype CrmProfile = {\n  id: string\n  name: string\n  createdAt: string\n  updatedAt: string\n}\n\ntype StoredCrmData = { contacts?: Contact[]; tasks?: Task[]; conversations?: ConversationRecord[] }\n\nconst LEGACY_STORAGE_KEY = 'relazione-crm-personale-v1'\nconst PROFILE_LIST_KEY = 'relazione-crm-profili-v1'\nconst ACTIVE_PROFILE_KEY = 'relazione-crm-profilo-attivo-v1'\nfunction profileStorageKey(profileId: string) { return `${LEGACY_STORAGE_KEY}:${profileId}` }")

s = s.replace("  const [contacts, setContacts] = useState<Contact[]>([])\n  const [tasks, setTasks] = useState<Task[]>([])\n  const [conversations, setConversations] = useState<ConversationRecord[]>([])", "  const [profiles, setProfiles] = useState<CrmProfile[]>([])\n  const [activeProfileId, setActiveProfileId] = useState('')\n  const [newProfileName, setNewProfileName] = useState('')\n  const [contacts, setContacts] = useState<Contact[]>([])\n  const [tasks, setTasks] = useState<Task[]>([])\n  const [conversations, setConversations] = useState<ConversationRecord[]>([])")

old_effect = """  useEffect(() => {\n    try {\n      const stored = window.localStorage.getItem(STORAGE_KEY)\n      if (stored) {\n        const parsed = JSON.parse(stored) as { contacts?: Contact[]; tasks?: Task[]; conversations?: ConversationRecord[] }\n        setContacts(Array.isArray(parsed.contacts) ? parsed.contacts : [])\n        setTasks(Array.isArray(parsed.tasks) ? parsed.tasks : [])\n        setConversations(Array.isArray(parsed.conversations) ? parsed.conversations : [])\n        setSelectedContactId(parsed.contacts?.[0]?.id || '')\n      }\n    } catch { window.localStorage.removeItem(STORAGE_KEY) }\n    setHydrated(true)\n  }, [])\n\n  useEffect(() => {\n    if (hydrated) window.localStorage.setItem(STORAGE_KEY, JSON.stringify({ contacts, tasks, conversations }))\n  }, [contacts, tasks, conversations, hydrated])\n"""
new_effect = """  function loadProfileData(profileId: string, useLegacyFallback = false) {\n    try {\n      const stored = window.localStorage.getItem(profileStorageKey(profileId)) || (useLegacyFallback ? window.localStorage.getItem(LEGACY_STORAGE_KEY) : null)\n      if (stored) {\n        const parsed = JSON.parse(stored) as StoredCrmData\n        const nextContacts = Array.isArray(parsed.contacts) ? parsed.contacts : []\n        setContacts(nextContacts)\n        setTasks(Array.isArray(parsed.tasks) ? parsed.tasks : [])\n        setConversations(Array.isArray(parsed.conversations) ? parsed.conversations : [])\n        setSelectedContactId(nextContacts[0]?.id || '')\n        return\n      }\n    } catch { window.localStorage.removeItem(profileStorageKey(profileId)) }\n    setContacts([])\n    setTasks([])\n    setConversations([])\n    setSelectedContactId('')\n    setAnalysis(null)\n  }\n\n  useEffect(() => {\n    try {\n      const savedProfiles = window.localStorage.getItem(PROFILE_LIST_KEY)\n      let parsedProfiles = savedProfiles ? JSON.parse(savedProfiles) as CrmProfile[] : []\n      if (!Array.isArray(parsedProfiles) || parsedProfiles.length === 0) {\n        const timestamp = nowIso()\n        parsedProfiles = [{ id: 'profilo-io', name: 'Io', createdAt: timestamp, updatedAt: timestamp }]\n        window.localStorage.setItem(PROFILE_LIST_KEY, JSON.stringify(parsedProfiles))\n      }\n      const savedActive = window.localStorage.getItem(ACTIVE_PROFILE_KEY)\n      const nextActive = parsedProfiles.find((profile) => profile.id === savedActive)?.id || parsedProfiles[0].id\n      setProfiles(parsedProfiles)\n      setActiveProfileId(nextActive)\n      window.localStorage.setItem(ACTIVE_PROFILE_KEY, nextActive)\n      loadProfileData(nextActive, nextActive === parsedProfiles[0].id)\n    } catch {\n      const timestamp = nowIso()\n      const fallback = [{ id: 'profilo-io', name: 'Io', createdAt: timestamp, updatedAt: timestamp }]\n      setProfiles(fallback)\n      setActiveProfileId(fallback[0].id)\n      loadProfileData(fallback[0].id, true)\n    }\n    setHydrated(true)\n  }, [])\n\n  useEffect(() => {\n    if (hydrated && activeProfileId) window.localStorage.setItem(profileStorageKey(activeProfileId), JSON.stringify({ contacts, tasks, conversations }))\n  }, [contacts, tasks, conversations, hydrated, activeProfileId])\n\n  useEffect(() => {\n    if (hydrated) window.localStorage.setItem(PROFILE_LIST_KEY, JSON.stringify(profiles))\n  }, [profiles, hydrated])\n"""
if old_effect not in s:
    raise SystemExit('old effect block not found')
s = s.replace(old_effect, new_effect)

s = s.replace("  const selectedContact = useMemo(() => contacts.find((c) => c.id === selectedContactId) || contacts[0], [contacts, selectedContactId])", "  const activeProfile = useMemo(() => profiles.find((profile) => profile.id === activeProfileId), [profiles, activeProfileId])\n  const selectedContact = useMemo(() => contacts.find((c) => c.id === selectedContactId) || contacts[0], [contacts, selectedContactId])")

s = s.replace("  function askAgent(prompt?: string) { const q = prompt || question; setQuestion(q); setAnswer(agentAnswer(q, contacts, tasks, conversations)) }\n  function exportData() { const blob = new Blob([JSON.stringify({ contacts, tasks, conversations }, null, 2)], { type: 'application/json' }); const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = `relazione-crm-backup-${today()}.json`; a.click(); URL.revokeObjectURL(url) }\n  function clearAllData() { if (!window.confirm('Vuoi cancellare tutti i dati locali del CRM personale?')) return; setContacts([]); setTasks([]); setConversations([]); setSelectedContactId(''); resetDraft(); setAnalysis(null); setAnswer('Dati cancellati. Puoi ricominciare inserendo i tuoi contatti reali.') }", "  function askAgent(prompt?: string) { const q = prompt || question; setQuestion(q); setAnswer(agentAnswer(q, contacts, tasks, conversations)) }\n  function switchProfile(profileId: string) { setActiveProfileId(profileId); window.localStorage.setItem(ACTIVE_PROFILE_KEY, profileId); loadProfileData(profileId); resetDraft(); setAnalysis(null); setAnswer('Profilo cambiato. Sto usando solo i dati locali di questo profilo.') }\n  function createProfile() { const name = newProfileName.trim(); if (!name) return; const timestamp = nowIso(); const newProfile = { id: id('profilo'), name, createdAt: timestamp, updatedAt: timestamp }; setProfiles((current) => [...current, newProfile]); setNewProfileName(''); setActiveProfileId(newProfile.id); window.localStorage.setItem(ACTIVE_PROFILE_KEY, newProfile.id); setContacts([]); setTasks([]); setConversations([]); setSelectedContactId(''); resetDraft(); setAnalysis(null); setAnswer(`Profilo ${name} creato. I dati saranno separati dagli altri profili locali.`) }\n  function exportData() { const blob = new Blob([JSON.stringify({ profile: activeProfile, contacts, tasks, conversations }, null, 2)], { type: 'application/json' }); const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = `relazione-crm-${activeProfile?.name || 'profilo'}-backup-${today()}.json`.replace(/\\s+/g, '-').toLowerCase(); a.click(); URL.revokeObjectURL(url) }\n  function importData(event: React.ChangeEvent<HTMLInputElement>) { const file = event.target.files?.[0]; if (!file) return; const reader = new FileReader(); reader.onload = () => { try { const parsed = JSON.parse(String(reader.result)) as StoredCrmData; const nextContacts = Array.isArray(parsed.contacts) ? parsed.contacts : []; const nextTasks = Array.isArray(parsed.tasks) ? parsed.tasks : []; const nextConversations = Array.isArray(parsed.conversations) ? parsed.conversations : []; setContacts(nextContacts); setTasks(nextTasks); setConversations(nextConversations); setSelectedContactId(nextContacts[0]?.id || ''); setAnswer('Backup importato nel profilo attivo. Gli altri profili non sono stati modificati.'); } catch { window.alert('Il file selezionato non sembra un backup valido del CRM.') } finally { event.target.value = '' } }; reader.readAsText(file) }\n  function clearAllData() { if (!window.confirm(`Vuoi cancellare solo i dati locali del profilo ${activeProfile?.name || 'attivo'}? Gli altri profili resteranno separati.`)) return; setContacts([]); setTasks([]); setConversations([]); setSelectedContactId(''); resetDraft(); setAnalysis(null); setAnswer('Dati del profilo attivo cancellati. Puoi ricominciare inserendo contatti reali.') }")

s = s.replace("<div className=\"text-xs text-gray-500\">Postazione personale</div>", "<div className=\"text-xs text-gray-500\">Postazione privata</div>")
s = s.replace("<strong className=\"block mb-1\">Uso personale attivo</strong>I dati vengono salvati nel tuo browser. Puoi iniziare gratis, senza Supabase o SaaS esterni.", "<strong className=\"block mb-1\">Uso privato gratuito</strong>Ogni profilo locale ha dati separati. Nessun contatto viene condiviso tra soci.")
s = s.replace("<h1 className=\"text-3xl font-bold tracking-tight\">CRM AI Relazionale Personale</h1><p className=\"text-gray-500 mt-1\">Gestisci i tuoi contatti reali, conversazioni, task e follow-up. I dati restano salvati nel browser.</p>", "<h1 className=\"text-3xl font-bold tracking-tight\">CRM AI Relazionale Privato</h1><p className=\"text-gray-500 mt-1\">Usalo tu e, se vuoi, anche i tuoi soci: ogni profilo locale gestisce solo i propri contatti.</p>")

profile_panel = """</header><section className=\"mb-8 rounded-3xl border bg-white p-5\"><div className=\"flex flex-col xl:flex-row xl:items-end gap-4 justify-between\"><div><div className=\"flex items-center gap-2 text-sm font-semibold text-blue-800\"><ShieldCheck className=\"w-4 h-4\" /> Spazi separati per uso interno</div><p className=\"text-gray-600 mt-1\">Profilo attivo: <strong>{activeProfile?.name || 'Profilo locale'}</strong>. I contatti, le conversazioni e i task di questo profilo sono salvati separatamente nel browser e non vengono mostrati agli altri profili.</p></div><div className=\"flex flex-col md:flex-row gap-2 md:items-center\"><select value={activeProfileId} onChange={(e) => switchProfile(e.target.value)} className=\"rounded-2xl border px-4 py-3 bg-white min-w-48\">{profiles.map((profile) => <option key={profile.id} value={profile.id}>{profile.name}</option>)}</select><div className=\"flex gap-2\"><input value={newProfileName} onChange={(e) => setNewProfileName(e.target.value)} className=\"rounded-2xl border px-4 py-3 w-48\" placeholder=\"Nome socio/profilo\" /><button onClick={createProfile} className=\"rounded-2xl bg-blue-700 text-white px-4 py-3 font-semibold hover:bg-blue-800\"><UserPlus className=\"w-4 h-4 inline mr-2\" />Crea profilo</button></div></div></div></section>"""
s = s.replace("</header>", profile_panel, 1)

s = s.replace("<button onClick={exportData} className=\"px-4 py-2 rounded-xl border bg-white hover:bg-stone-50 text-sm inline-flex items-center gap-2\"><Download className=\"w-4 h-4\" />Backup</button><button onClick={clearAllData}", "<button onClick={exportData} className=\"px-4 py-2 rounded-xl border bg-white hover:bg-stone-50 text-sm inline-flex items-center gap-2\"><Download className=\"w-4 h-4\" />Backup profilo</button><label className=\"px-4 py-2 rounded-xl border bg-white hover:bg-stone-50 text-sm inline-flex items-center gap-2 cursor-pointer\"><Upload className=\"w-4 h-4\" />Importa<input type=\"file\" accept=\"application/json\" onChange={importData} className=\"hidden\" /></label><button onClick={clearAllData}")

s = s.replace("In questa versione gratuita l’agente usa regole locali e i dati salvati nel browser. Collegando Claude e Supabase potrà diventare un agente AI reale multi-dispositivo.", "In questa versione gratuita l’agente usa regole locali e solo i dati del profilo attivo. I profili dei soci restano separati. Supabase e AI esterna si possono aggiungere in futuro solo se serviranno sincronizzazione e modelli reali.")

path.write_text(s)
print('refactor profili completato')
